```cpp
#include <iostream>
#include <fstream>
#include <string>

using namespace std;

int main() {
    string filename, word;
    cout << "Enter the filename: ";
    getline(cin, filename);
    cout << "Enter the word to search for: ";
    getline(cin, word);

    ifstream file(filename);

    if (!file) {
        cerr << "Unable to open file" << endl;
        return 1;
    }

    int count = 0, lineNo = 1;

    while (file) {
        string line;
        getline(file, line);

        if (line.empty()) {
            lineNo--;
            continue;
        }

        lineNo++;

        size_t pos = line.find(word);
        while (pos != string::npos) {
            count++;
            pos = line.find(word, pos + 1));
        }
    }

    file.close();

    cout << "Number of occurrences of \"" << word << "\" in the file \"" << filename << "\" is: " << count << endl;

    return 0;
}
